insert into questions (question, options, correct_index, explanation) values ('Complete a sequência lógica: 2, 6, 12, 20, 30, ?', '["36","40","42","38"]'::jsonb, 2, 'A diferença entre os termos cresce de 2 em 2 (4, 6, 8, 10, 12), então 30 + 12 = 42.');
insert into questions (question, options, correct_index, explanation) values ('Qual número não pertence ao grupo: 3, 5, 7, 10, 11?', '["3","7","10","11"]'::jsonb, 2, 'Todos os outros números são ímpares; o 10 é o único número par do grupo.');
insert into questions (question, options, correct_index, explanation) values ('Charada: quanto mais eu seco, mais molhado fico. O que sou?', '["Uma esponja","Uma toalha","Um guarda-chuva","Um espelho"]'::jsonb, 1, 'A toalha é usada para secar algo, mas no processo ela mesma fica molhada.');
insert into questions (question, options, correct_index, explanation) values ('Se hoje é quarta-feira, que dia da semana será daqui a 100 dias?', '["Segunda-feira","Sexta-feira","Quinta-feira","Sábado"]'::jsonb, 1, '100 dividido por 7 deixa resto 2, então avançamos 2 dias a partir de quarta: quinta, sexta.');
insert into questions (question, options, correct_index, explanation) values ('Qual é a próxima letra da sequência: A, D, G, J, ?', '["K","L","M","N"]'::jsonb, 2, 'A sequência pula sempre 2 letras (A→D→G→J→M), avançando de 3 em 3 posições no alfabeto.');
insert into questions (question, options, correct_index, explanation) values ('Charada: tenho cidades, mas nenhuma casa; tenho montanhas, mas nenhuma árvore; tenho água, mas nenhum peixe. O que sou?', '["Um globo","Um mapa","Um livro","Uma foto"]'::jsonb, 1, 'Um mapa representa cidades, montanhas e rios sem conter os elementos reais.');
insert into questions (question, options, correct_index, explanation) values ('Se um relógio leva 5 segundos para bater 6 badaladas, quanto tempo leva para bater 12 badaladas?', '["10 segundos","11 segundos","12 segundos","6 segundos"]'::jsonb, 1, 'Entre 6 badaladas há 5 intervalos (1s cada). Para 12 badaladas há 11 intervalos, ou seja, 11 segundos.');
insert into questions (question, options, correct_index, explanation) values ('Qual figura completa a sequência: círculo, quadrado, triângulo, círculo, quadrado, ?', '["Círculo","Triângulo","Quadrado","Pentágono"]'::jsonb, 1, 'O padrão se repete a cada 3 posições: círculo, quadrado, triângulo — o próximo é triângulo.');
insert into questions (question, options, correct_index, explanation) values ('Charada: quanto mais você tira de mim, maior eu fico. O que sou?', '["Um buraco","Uma dívida","Um problema","Uma sombra"]'::jsonb, 0, 'Ao retirar terra de um buraco, ele aumenta de tamanho.');
insert into questions (question, options, correct_index, explanation) values ('Ana é mais velha que Bruno. Bruno é mais velho que Carla. Quem é o mais novo dos três?', '["Ana","Bruno","Carla","Não é possível saber"]'::jsonb, 2, 'Se Ana > Bruno > Carla em idade, Carla é necessariamente a mais nova.');
insert into questions (question, options, correct_index, explanation) values ('Qual é o próximo número da sequência de Fibonacci: 1, 1, 2, 3, 5, 8, ?', '["11","12","13","10"]'::jsonb, 2, 'Cada número é a soma dos dois anteriores: 5 + 8 = 13.');
insert into questions (question, options, correct_index, explanation) values ('Charada: eu tenho chaves, mas não abro portas. Tenho espaço, mas não tenho quarto. Você pode entrar, mas não pode sair. O que sou?', '["Um piano","Um teclado de computador","Uma casa","Um cofre"]'::jsonb, 1, 'Um teclado tem ''teclas'' (chaves), ''barra de espaço'' e você pode digitar ''enter'' (entrar), mas não ''sair'' como tecla padrão.');
insert into questions (question, options, correct_index, explanation) values ('Se todos os Bips são Bops, e todos os Bops são Baps, então:', '["Todos os Baps são Bips","Todos os Bips são Baps","Nenhum Bip é Bap","Alguns Baps não são Bops"]'::jsonb, 1, 'Por transitividade lógica: se Bip ⊂ Bop e Bop ⊂ Bap, então Bip ⊂ Bap.');
insert into questions (question, options, correct_index, explanation) values ('Qual planeta do sistema solar é conhecido como o ''Planeta Vermelho''?', '["Vênus","Júpiter","Marte","Saturno"]'::jsonb, 2, 'Marte tem coloração avermelhada devido ao óxido de ferro presente em sua superfície.');
insert into questions (question, options, correct_index, explanation) values ('Um trem parte às 14h e viaja a 80 km/h. Outro trem parte da mesma cidade às 15h no mesmo sentido, a 100 km/h. A que horas o segundo trem alcança o primeiro?', '["18h","19h","20h","17h"]'::jsonb, 1, 'Às 15h o primeiro já percorreu 80 km. A diferença de velocidade é 20 km/h, então leva 4h para alcançar: 15h + 4h = 19h.');
insert into questions (question, options, correct_index, explanation) values ('Complete a sequência: 1, 4, 9, 16, 25, ?', '["30","36","32","49"]'::jsonb, 1, 'São os quadrados perfeitos (1², 2², 3², 4², 5²...). O próximo é 6² = 36.');
insert into questions (question, options, correct_index, explanation) values ('Charada: não tenho vida, mas posso morrer. O que sou?', '["Uma pilha","Uma planta","Um robô","Uma estrela"]'::jsonb, 0, 'Uma pilha nunca esteve viva, mas dizemos que ela ''morre'' quando descarrega.');
insert into questions (question, options, correct_index, explanation) values ('Se 5 máquinas fazem 5 produtos em 5 minutos, quanto tempo levam 100 máquinas para fazer 100 produtos?', '["100 minutos","20 minutos","5 minutos","50 minutos"]'::jsonb, 2, 'Cada máquina faz 1 produto em 5 minutos. Com 100 máquinas trabalhando em paralelo, ainda leva 5 minutos para produzir 100 produtos.');
insert into questions (question, options, correct_index, explanation) values ('Complete a sequência: 3, 9, 27, 81, ?', '["162","243","324","729"]'::jsonb, 1, 'Cada termo é o anterior multiplicado por 3 (potências de 3). 81 × 3 = 243.');
insert into questions (question, options, correct_index, explanation) values ('Charada: quanto mais eu cresço, menos você vê. O que sou?', '["A escuridão","A neblina","A fumaça","A distância"]'::jsonb, 0, 'Quanto mais a escuridão aumenta, menos enxergamos ao redor.');
insert into questions (question, options, correct_index, explanation) values ('Qual é o maior oceano do mundo?', '["Atlântico","Índico","Ártico","Pacífico"]'::jsonb, 3, 'O Oceano Pacífico é o maior e mais profundo oceano da Terra, cobrindo cerca de um terço da superfície do planeta.');
insert into questions (question, options, correct_index, explanation) values ('Um pai tem 5 filhas. Cada filha tem exatamente 1 irmão. Quantos filhos o pai tem ao todo?', '["5","6","10","11"]'::jsonb, 1, 'As 5 filhas compartilham o mesmo único irmão. Logo, são 5 filhas + 1 filho = 6 filhos no total.');
insert into questions (question, options, correct_index, explanation) values ('Complete a sequência de letras: Z, X, V, T, ?', '["S","R","Q","U"]'::jsonb, 1, 'A sequência anda de trás para frente pulando uma letra a cada passo (Z, X, V, T, R).');
insert into questions (question, options, correct_index, explanation) values ('Charada: tenho um rosto, mas não tenho olhos; tenho mãos, mas não tenho dedos. O que sou?', '["Uma boneca","Um relógio","Uma estátua","Um espelho"]'::jsonb, 1, 'Um relógio tem ''rosto'' (mostrador) e ''mãos'' (ponteiros), mas não possui olhos nem dedos de verdade.');
insert into questions (question, options, correct_index, explanation) values ('Quantos lados tem um hexágono?', '["5","6","7","8"]'::jsonb, 1, 'O prefixo ''hexa'' significa seis — um hexágono é um polígono de 6 lados.');
insert into questions (question, options, correct_index, explanation) values ('Você está correndo uma corrida e ultrapassa quem está em segundo lugar. Em que posição você fica?', '["Primeiro lugar","Segundo lugar","Terceiro lugar","Depende da distância que falta"]'::jsonb, 1, 'Se você ultrapassa o segundo colocado, você assume a posição dele: o segundo lugar (e não o primeiro).');
insert into questions (question, options, correct_index, explanation) values ('Complete a sequência: 2, 5, 11, 23, 47, ?', '["94","95","96","93"]'::jsonb, 1, 'Cada termo é o dobro do anterior mais 1 (2×2+1=5, 5×2+1=11...). 47×2+1 = 95.');
insert into questions (question, options, correct_index, explanation) values ('Charada: quanto mais você tira de mim, mais eu deixo para trás. O que sou?', '["Pegadas","Lembranças","Um rastro de tinta","Um caminho"]'::jsonb, 0, 'A cada passo que você dá (tira de si mesmo), mais pegadas ficam para trás.');
insert into questions (question, options, correct_index, explanation) values ('Qual é o único metal que é líquido à temperatura ambiente?', '["Chumbo","Mercúrio","Estanho","Zinco"]'::jsonb, 1, 'O mercúrio é o único metal que se mantém em estado líquido em temperatura ambiente.');
insert into questions (question, options, correct_index, explanation) values ('Se A=1, B=2, C=3, D=4... qual é a soma dos valores das letras da palavra ''CAB''?', '["5","6","7","8"]'::jsonb, 1, 'C=3, A=1, B=2. Somando: 3 + 1 + 2 = 6.');
insert into questions (question, options, correct_index, explanation) values ('Complete a sequência: 5, 10, 20, 40, 80, ?', '["120","150","160","100"]'::jsonb, 2, 'Cada termo é o dobro do anterior. 80 × 2 = 160.');
insert into questions (question, options, correct_index, explanation) values ('Complete a sequência: 100, 90, 81, 73, ?', '["68","66","64","70"]'::jsonb, 1, 'As diferenças diminuem 1 a cada passo (-10, -9, -8, -7). 73 - 7 = 66.');
insert into questions (question, options, correct_index, explanation) values ('Complete a sequência: 7, 14, 28, 56, ?', '["84","98","112","106"]'::jsonb, 2, 'Cada termo é o dobro do anterior. 56 × 2 = 112.');
insert into questions (question, options, correct_index, explanation) values ('Complete a sequência: 1, 2, 4, 7, 11, 16, ?', '["20","21","22","23"]'::jsonb, 2, 'As diferenças aumentam 1 a cada passo (1,2,3,4,5,6). 16 + 6 = 22.');
insert into questions (question, options, correct_index, explanation) values ('Complete a sequência: 2, 3, 5, 8, 13, 21, ?', '["29","31","34","36"]'::jsonb, 2, 'Cada termo é a soma dos dois anteriores (sequência de Fibonacci). 13 + 21 = 34.');
insert into questions (question, options, correct_index, explanation) values ('Complete a sequência: 4, 8, 16, 32, ?', '["48","56","64","72"]'::jsonb, 2, 'Cada termo é o dobro do anterior. 32 × 2 = 64.');
insert into questions (question, options, correct_index, explanation) values ('Complete a sequência: 10, 20, 15, 25, 20, 30, ?', '["35","25","40","20"]'::jsonb, 1, 'O padrão alterna +10 e -5. Depois de 30, subtraímos 5: 30 - 5 = 25.');
insert into questions (question, options, correct_index, explanation) values ('Complete a sequência: 81, 27, 9, 3, ?', '["0","1","2","-3"]'::jsonb, 1, 'Cada termo é dividido por 3. 3 ÷ 3 = 1.');
insert into questions (question, options, correct_index, explanation) values ('Complete a sequência: 2, 6, 18, 54, ?', '["108","144","162","216"]'::jsonb, 2, 'Cada termo é multiplicado por 3. 54 × 3 = 162.');
insert into questions (question, options, correct_index, explanation) values ('Complete a sequência: 1, 8, 27, 64, ?', '["100","121","125","81"]'::jsonb, 2, 'São cubos perfeitos (1³, 2³, 3³, 4³...). O próximo é 5³ = 125.');
insert into questions (question, options, correct_index, explanation) values ('Complete a sequência: 15, 13, 16, 14, 17, 15, ?', '["16","18","19","20"]'::jsonb, 1, 'O padrão alterna -2 e +3. Depois de 15, somamos 3: 15 + 3 = 18.');
insert into questions (question, options, correct_index, explanation) values ('Complete a sequência: 3, 4, 6, 9, 13, ?', '["16","17","18","19"]'::jsonb, 2, 'As diferenças aumentam 1 a cada passo (1,2,3,4,5). 13 + 5 = 18.');
insert into questions (question, options, correct_index, explanation) values ('Complete a sequência: 2, 4, 8, 14, 22, ?', '["30","32","34","28"]'::jsonb, 1, 'As diferenças aumentam 2 a cada passo (2,4,6,8,10). 22 + 10 = 32.');
insert into questions (question, options, correct_index, explanation) values ('Complete a sequência: 50, 47, 44, 41, ?', '["37","38","39","40"]'::jsonb, 1, 'Cada termo diminui 3. 41 - 3 = 38.');
insert into questions (question, options, correct_index, explanation) values ('Complete a sequência: 6, 11, 21, 41, ?', '["61","71","81","91"]'::jsonb, 2, 'Cada termo é o dobro do anterior menos 1. 41 × 2 - 1 = 81.');
insert into questions (question, options, correct_index, explanation) values ('Charada: eu subo e desço o dia todo, mas nunca saio do lugar. O que sou?', '["Uma escada","Um elevador","Um balanço","Um foguete"]'::jsonb, 1, 'O elevador se move para cima e para baixo, mas está sempre fixo no mesmo poço.');
insert into questions (question, options, correct_index, explanation) values ('Charada: eu te sigo o dia todo, mas desapareço quando escurece. O que sou?', '["Seu reflexo","Sua sombra","Seu eco","Seu cabelo"]'::jsonb, 1, 'A sombra acompanha você durante o dia, mas some sem luz.');
insert into questions (question, options, correct_index, explanation) values ('Charada: não tenho boca, mas falo; não tenho ouvidos, mas escuto. O que sou?', '["Um rádio","Um papagaio","Um eco","Um telefone"]'::jsonb, 2, 'O eco repete os sons que ouve, sem ter boca nem ouvidos de verdade.');
insert into questions (question, options, correct_index, explanation) values ('Charada: quanto mais eu envelheço, mais valho. O que sou?', '["Um carro","Um vinho","Um celular","Um jornal"]'::jsonb, 1, 'Diferente da maioria dos produtos, alguns vinhos ficam mais valiosos com o tempo.');
insert into questions (question, options, correct_index, explanation) values ('Charada: tenho uma coroa na cabeça, mas não sou rei nem rainha. O que sou?', '["Um abacaxi","Uma batata","Uma flor","Um chapéu"]'::jsonb, 0, 'O topo do abacaxi lembra uma coroa, apesar de ele não ser realeza.');
insert into questions (question, options, correct_index, explanation) values ('Charada: corro sem pernas, mas nunca chego a lugar nenhum. O que sou?', '["Um carro","Um rio","Um trem","Um cavalo"]'::jsonb, 1, 'Um rio ''corre'' continuamente, mas seu leito permanece no mesmo lugar.');
insert into questions (question, options, correct_index, explanation) values ('Charada: quanto mais escuro está, mais fácil sou de ver. O que sou?', '["Uma lanterna","Uma estrela","Uma sombra","Um espelho"]'::jsonb, 1, 'As estrelas ficam mais visíveis quanto mais escuro o céu estiver.');
insert into questions (question, options, correct_index, explanation) values ('Charada: quanto mais eu como, mais eu cresço, mas um gole de água me mata. O que sou?', '["O fogo","Uma planta","Um balão","Um vírus"]'::jsonb, 0, 'O fogo se alimenta de combustível e cresce, mas a água o apaga.');
insert into questions (question, options, correct_index, explanation) values ('Charada: posso ser quebrada sem nunca ser tocada. O que sou?', '["Uma promessa","Uma janela","Uma corda","Uma xícara"]'::jsonb, 0, 'Uma promessa é quebrada quando não é cumprida, sem envolver nada físico.');
insert into questions (question, options, correct_index, explanation) values ('Charada: viajo o mundo inteiro, mas fico sempre presa num canto do envelope. O que sou?', '["Uma carta","Um selo","Uma etiqueta","Uma foto"]'::jsonb, 1, 'O selo postal viaja grudado no envelope até o destino.');
insert into questions (question, options, correct_index, explanation) values ('Charada: quanto mais eu trabalho, menor eu fico. O que sou?', '["Um sabonete","Um lápis","Uma vela","Todas as anteriores"]'::jsonb, 3, 'Sabonete, lápis e vela diminuem de tamanho conforme são usados.');
insert into questions (question, options, correct_index, explanation) values ('Charada: tenho folhas, mas não sou árvore; tenho lombada, mas não tenho coluna. O que sou?', '["Um livro","Uma planta","Uma mesa","Um caderno"]'::jsonb, 0, 'Um livro tem ''folhas'' (páginas) e uma ''lombada'', sem ser uma árvore ou ter espinha dorsal.');
insert into questions (question, options, correct_index, explanation) values ('Charada: posso voar sem asas e posso chorar sem ter olhos. O que sou?', '["Uma pipa","Uma nuvem","Um avião","Um pássaro"]'::jsonb, 1, 'As nuvens se movem pelo céu sem asas e liberam chuva, como se ''chorassem''.');
insert into questions (question, options, correct_index, explanation) values ('Charada: sou leve como o ar, mas nem a pessoa mais forte consegue me segurar por muito tempo. O que sou?', '["A respiração","Uma pena","Um balão","O vento"]'::jsonb, 0, 'Todo mundo precisa soltar a respiração eventualmente, por mais que tente prendê-la.');
insert into questions (question, options, correct_index, explanation) values ('Charada: tenho um olho só e não posso enxergar. O que sou?', '["Uma agulha","Um furacão","Uma câmera","Um relógio"]'::jsonb, 0, 'O ''olho'' da agulha é o buraco por onde passa a linha.');
insert into questions (question, options, correct_index, explanation) values ('Charada: no verão fico roxa e docinha, mas sob o sol forte viro passa. O que sou?', '["Uma ameixa","Uma uva","Uma ciruela","Uma ervilha"]'::jsonb, 1, 'A uva, quando desidratada ao sol, se transforma em uva-passa.');
insert into questions (question, options, correct_index, explanation) values ('Charada: nasço no mar, mas dou sabor à sua comida até o fim. O que sou?', '["O sal","O iodo","A alga","O plâncton"]'::jsonb, 0, 'O sal é extraído da água do mar (ou de minas) e usado para temperar alimentos.');
insert into questions (question, options, correct_index, explanation) values ('Charada: tenho cabeça e cauda, mas não tenho corpo. O que sou?', '["Uma moeda","Um cometa","Uma cobra","Uma seta"]'::jsonb, 0, 'As moedas têm um lado ''cara'' (cabeça) e o outro é às vezes chamado de ''coroa'' ou ''cauda''.');
insert into questions (question, options, correct_index, explanation) values ('Charada: viro de cabeça para baixo e começo a contar o tempo. O que sou?', '["Um relógio digital","Uma ampulheta","Um cronômetro","Um calendário"]'::jsonb, 1, 'A ampulheta só começa a marcar o tempo quando é virada de cabeça para baixo.');
insert into questions (question, options, correct_index, explanation) values ('Charada: tenho dentes, mas nunca mastigo. O que sou?', '["Um garfo","Um pente","Uma serra","Um zíper"]'::jsonb, 1, 'O pente tem ''dentes'' que penteiam o cabelo, mas não mastiga nada.');
insert into questions (question, options, correct_index, explanation) values ('Três amigos dividiram uma pizza em partes iguais. Cada um comeu 4 pedaços e não sobrou nada. Quantos pedaços tinha a pizza?', '["8","10","12","14"]'::jsonb, 2, '3 amigos × 4 pedaços cada = 12 pedaços ao todo.');
insert into questions (question, options, correct_index, explanation) values ('Se 1 ovo leva 10 minutos para cozinhar em água fervente, quanto tempo levam 3 ovos para cozinhar juntos na mesma panela?', '["30 minutos","20 minutos","10 minutos","15 minutos"]'::jsonb, 2, 'Os ovos cozinham ao mesmo tempo dentro da mesma água fervente, então o tempo não muda.');
insert into questions (question, options, correct_index, explanation) values ('Um fazendeiro tinha 17 ovelhas. Todas menos 9 morreram. Quantas ovelhas sobraram?', '["8","9","17","0"]'::jsonb, 1, '''Todas menos 9 morreram'' significa que 9 ovelhas continuam vivas.');
insert into questions (question, options, correct_index, explanation) values ('Quantos meses do ano têm 28 dias?', '["1","2","6","Todos os 12"]'::jsonb, 3, 'Pegadinha clássica: todo mês tem PELO MENOS 28 dias, então, tecnicamente, os 12 meses têm 28 dias.');
insert into questions (question, options, correct_index, explanation) values ('Você entra em um quarto escuro com apenas 1 fósforo. Há uma vela, uma lamparina a óleo e uma lareira para acender. O que você acende primeiro?', '["A vela","A lamparina","A lareira","O fósforo"]'::jsonb, 3, 'Antes de acender qualquer coisa, é preciso acender o próprio fósforo.');
insert into questions (question, options, correct_index, explanation) values ('Dois pais e dois filhos foram pescar, e cada um pegou exatamente 1 peixe — totalizando 3 peixes. Como isso é possível?', '["Eram avô, pai e filho (3 pessoas)","Um peixe foi contado duas vezes","Eram 4 pessoas ao todo","Isso não é possível"]'::jsonb, 0, 'Avô, pai e filho formam ''2 pais e 2 filhos'' ao mesmo tempo, mas são apenas 3 pessoas.');
insert into questions (question, options, correct_index, explanation) values ('Um homem baixinho mora no 10º andar. Ele sempre desce de elevador até o térreo, mas ao voltar só consegue subir de elevador até o 7º andar, fazendo o resto a pé — exceto em dias de chuva, quando sobe direto até o 10º andar de elevador. Por quê?', '["Ele gosta de se exercitar","Em dias de chuva, ele usa a ponta do guarda-chuva para apertar o botão do 10º andar","O elevador só funciona até o 7º andar quando não chove","Ele mora, na verdade, no 7º andar"]'::jsonb, 1, 'Sendo baixinho, ele só alcança o botão do 7º andar normalmente, mas com o guarda-chuva consegue apertar o botão mais alto.');
insert into questions (question, options, correct_index, explanation) values ('Uma família tem 6 filhas, e cada filha tem exatamente 1 irmão. Contando os pais, quantas pessoas há na família ao todo?', '["7","8","9","10"]'::jsonb, 2, '6 filhas + 1 irmão (compartilhado por todas) + 2 pais = 9 pessoas.');
insert into questions (question, options, correct_index, explanation) values ('Em uma corrida, você ultrapassa a pessoa que está em último lugar. Em que posição você fica?', '["Penúltimo lugar","Último lugar","Isso é impossível","Depende da distância que falta"]'::jsonb, 2, 'Não existe ninguém atrás do último colocado para você ultrapassar — a situação descrita não pode acontecer.');
insert into questions (question, options, correct_index, explanation) values ('Quantas vezes o algarismo 9 aparece escrito nos números de 1 a 100?', '["10","19","20","11"]'::jsonb, 2, 'O 9 aparece 10 vezes como algarismo das unidades (9,19,...,99) e mais 10 vezes como dezena (90 a 99), totalizando 20.');
insert into questions (question, options, correct_index, explanation) values ('Um produto custa R$100 na compra. Ao vendê-lo com 20% de lucro sobre o valor de compra, qual é o preço de venda?', '["R$110","R$115","R$120","R$130"]'::jsonb, 2, '20% de R$100 é R$20. Somando: R$100 + R$20 = R$120.');
insert into questions (question, options, correct_index, explanation) values ('Numa sala há 3 interruptores que controlam 3 lâmpadas em outro cômodo, fora da sua visão. Você só pode entrar nesse cômodo uma única vez. Como descobrir com certeza qual interruptor liga qual lâmpada?', '["É impossível descobrir com uma única entrada","Ligar um interruptor, esperar alguns minutos, desligá-lo, ligar outro e então entrar","Ligar todos os interruptores ao mesmo tempo e entrar","Perguntar para outra pessoa que já sabe"]'::jsonb, 1, 'Ao entrar: a lâmpada acesa corresponde ao 2º interruptor; a apagada e quente, ao 1º; a apagada e fria, ao 3º.');
insert into questions (question, options, correct_index, explanation) values ('Se SEG=1, TER=2, QUA=3, QUI=4... quanto vale SEX?', '["4","5","6","7"]'::jsonb, 1, 'Seguindo a ordem dos dias úteis da semana, sexta-feira é o 5º dia.');
insert into questions (question, options, correct_index, explanation) values ('Um trem de 200 metros de comprimento atravessa um túnel de 300 metros, andando a 50 metros por segundo. Quanto tempo leva para o trem atravessar completamente o túnel?', '["6 segundos","8 segundos","10 segundos","12 segundos"]'::jsonb, 2, 'A distância total até a traseira do trem sair do túnel é 200+300=500m. A 50m/s, isso leva 500 ÷ 50 = 10 segundos.');
insert into questions (question, options, correct_index, explanation) values ('2 pedreiros constroem um muro em 6 dias. Trabalhando no mesmo ritmo, quantos dias 3 pedreiros levariam para construir o mesmo muro?', '["3 dias","4 dias","5 dias","2 dias"]'::jsonb, 1, 'O trabalho total é 2×6=12 ''pedreiro-dias''. Com 3 pedreiros: 12 ÷ 3 = 4 dias.');
insert into questions (question, options, correct_index, explanation) values ('Numa gaveta escura há 5 meias pretas e 5 meias brancas, todas soltas. Quantas meias você precisa tirar, no mínimo, para garantir um par da mesma cor?', '["2","3","4","6"]'::jsonb, 1, 'Existem só 2 cores possíveis. Ao tirar 3 meias, pelo menos duas serão obrigatoriamente da mesma cor.');
insert into questions (question, options, correct_index, explanation) values ('Qual é o menor número inteiro positivo que, dividido por 2, 3, 4, 5 ou 6, sempre deixa resto 1?', '["31","41","61","121"]'::jsonb, 2, 'O mínimo múltiplo comum de 2,3,4,5,6 é 60. Somando 1, temos 61, que deixa resto 1 em todas essas divisões.');
insert into questions (question, options, correct_index, explanation) values ('Todos os gatos são mamíferos. Alguns mamíferos são pretos. O que se pode concluir com certeza?', '["Todo gato é preto","Nenhum gato é preto","Não é possível concluir que algum gato é preto","Todo mamífero é gato"]'::jsonb, 2, 'As premissas não garantem que os mamíferos pretos incluam algum gato — essa conclusão não é logicamente válida.');
insert into questions (question, options, correct_index, explanation) values ('Um relógio quebrado ficou parado e sempre marca a mesma hora. Quantas vezes por dia esse horário estará correto?', '["Nenhuma vez","1 vez","2 vezes","24 vezes"]'::jsonb, 2, 'Como o relógio marca sempre a mesma hora fixa, ela coincidirá com a hora certa duas vezes em 24 horas.');
insert into questions (question, options, correct_index, explanation) values ('Se hoje é sábado, que dia da semana será daqui a 45 dias?', '["Segunda-feira","Terça-feira","Quarta-feira","Domingo"]'::jsonb, 1, '45 dividido por 7 deixa resto 3. Avançando 3 dias a partir de sábado: domingo, segunda, terça-feira.');
insert into questions (question, options, correct_index, explanation) values ('Qual é o maior planeta do sistema solar?', '["Saturno","Netuno","Júpiter","Urano"]'::jsonb, 2, 'Júpiter é o maior planeta do sistema solar, com um diâmetro maior que o de todos os outros planetas somados.');
insert into questions (question, options, correct_index, explanation) values ('Aproximadamente quantos ossos tem o corpo humano adulto?', '["156","186","206","256"]'::jsonb, 2, 'O esqueleto humano adulto tem, em média, 206 ossos.');
insert into questions (question, options, correct_index, explanation) values ('Qual é a capital da Austrália?', '["Sydney","Melbourne","Camberra","Perth"]'::jsonb, 2, 'Apesar de Sydney ser mais famosa, a capital oficial da Austrália é Camberra.');
insert into questions (question, options, correct_index, explanation) values ('Quem pintou a Mona Lisa?', '["Michelangelo","Leonardo da Vinci","Rafael","Ticiano"]'::jsonb, 1, 'A Mona Lisa é uma das obras mais famosas de Leonardo da Vinci, pintada no início do século XVI.');
insert into questions (question, options, correct_index, explanation) values ('Qual rio é tradicionalmente considerado o mais longo do mundo?', '["Amazonas","Nilo","Mississippi","Yangtzé"]'::jsonb, 1, 'O Nilo é o mais citado como o mais longo pelos critérios tradicionais, embora estudos recentes sugiram que o Amazonas pode ser ainda mais extenso.');
insert into questions (question, options, correct_index, explanation) values ('Qual gás os seres humanos exalam ao respirar?', '["Oxigênio","Hidrogênio","Dióxido de carbono","Nitrogênio"]'::jsonb, 2, 'Ao expirar, os pulmões liberam principalmente dióxido de carbono (CO₂), produzido pelo metabolismo do corpo.');
insert into questions (question, options, correct_index, explanation) values ('Segundo a divisão mais usada no Brasil, quantos continentes existem?', '["5","6","7","4"]'::jsonb, 1, 'O modelo mais ensinado no Brasil considera 6 continentes: América, Europa, Ásia, África, Oceania e Antártida.');
insert into questions (question, options, correct_index, explanation) values ('Qual é o metal mais abundante na crosta terrestre?', '["Ferro","Alumínio","Cobre","Ouro"]'::jsonb, 1, 'O alumínio é o metal mais abundante na crosta terrestre, embora o ferro seja mais conhecido popularmente.');
insert into questions (question, options, correct_index, explanation) values ('Em que ano o ser humano pisou na Lua pela primeira vez?', '["1965","1969","1972","1959"]'::jsonb, 1, 'A missão Apollo 11 pousou na Lua em 20 de julho de 1969.');
insert into questions (question, options, correct_index, explanation) values ('Qual é o maior mamífero do mundo?', '["O elefante-africano","A girafa","A baleia-azul","O rinoceronte"]'::jsonb, 2, 'A baleia-azul é o maior animal já conhecido, podendo ultrapassar 30 metros de comprimento.');
insert into questions (question, options, correct_index, explanation) values ('Quantas cordas tem um violão clássico padrão?', '["4","5","6","7"]'::jsonb, 2, 'O violão clássico padrão tem 6 cordas.');
insert into questions (question, options, correct_index, explanation) values ('Qual é o osso mais longo do corpo humano?', '["A tíbia","O fêmur","O úmero","A fíbula"]'::jsonb, 1, 'O fêmur, localizado na coxa, é o osso mais longo e resistente do corpo humano.');
insert into questions (question, options, correct_index, explanation) values ('Qual é a moeda oficial do Japão?', '["O won","O yuan","O iene","O baht"]'::jsonb, 2, 'A moeda oficial do Japão é o iene (¥).');
insert into questions (question, options, correct_index, explanation) values ('Quem escreveu o romance ''Dom Casmurro''?', '["José de Alencar","Machado de Assis","Graciliano Ramos","Jorge Amado"]'::jsonb, 1, '''Dom Casmurro'' é uma das obras mais famosas de Machado de Assis, publicada em 1899.');
insert into questions (question, options, correct_index, explanation) values ('Qual é o menor país do mundo em área territorial?', '["Mônaco","San Marino","Vaticano","Liechtenstein"]'::jsonb, 2, 'O Vaticano tem cerca de 0,44 km², sendo o menor Estado soberano do mundo em área.');
insert into questions (question, options, correct_index, explanation) values ('Quantos lados tem um octógono?', '["6","7","8","9"]'::jsonb, 2, 'O prefixo ''octo'' significa oito — um octógono é um polígono de 8 lados.');
insert into questions (question, options, correct_index, explanation) values ('Qual elemento químico é representado pelo símbolo ''O''?', '["Ouro","Oxigênio","Ósmio","Ozônio"]'::jsonb, 1, 'O símbolo químico ''O'' representa o Oxigênio na tabela periódica.');
insert into questions (question, options, correct_index, explanation) values ('Em que continente fica o Egito?', '["Ásia","Oriente Médio","África","Europa"]'::jsonb, 2, 'O Egito está localizado no continente africano, embora a Península do Sinai fique tecnicamente na Ásia.');
insert into questions (question, options, correct_index, explanation) values ('Qual é, aproximadamente, a velocidade da luz no vácuo?', '["30 mil km/s","150 mil km/s","300 mil km/s","3 milhões km/s"]'::jsonb, 2, 'A velocidade da luz no vácuo é de aproximadamente 300.000 km por segundo.');
insert into questions (question, options, correct_index, explanation) values ('Quantas patas tem uma aranha?', '["6","8","10","4"]'::jsonb, 1, 'Aranhas são aracnídeos e possuem 8 patas, diferente dos insetos, que têm 6.');
insert into questions (question, options, correct_index, explanation) values ('Complete a sequência de letras: B, D, F, H, ?', '["I","J","K","G"]'::jsonb, 1, 'A sequência avança de 2 em 2 letras no alfabeto (pulando uma a cada passo).');
insert into questions (question, options, correct_index, explanation) values ('Complete a sequência de letras: A, C, F, J, ?', '["M","N","O","P"]'::jsonb, 2, 'O intervalo entre as letras aumenta 1 a cada passo (+2,+3,+4,+5). De J (10ª letra), somando 5, chega-se a O (15ª letra).');
insert into questions (question, options, correct_index, explanation) values ('Complete a sequência de letras: M, O, Q, S, ?', '["T","U","V","W"]'::jsonb, 1, 'A sequência avança de 2 em 2 letras (pulando uma a cada passo).');
insert into questions (question, options, correct_index, explanation) values ('Complete a sequência de letras: Y, W, U, S, ?', '["R","Q","P","T"]'::jsonb, 1, 'A sequência regride de 2 em 2 letras no alfabeto.');
insert into questions (question, options, correct_index, explanation) values ('Se A=1, B=2, C=3... qual letra corresponde ao número 15?', '["M","N","O","P"]'::jsonb, 2, 'Contando o alfabeto em ordem, a 15ª letra é o O.');
insert into questions (question, options, correct_index, explanation) values ('Complete a sequência: AB, DE, GH, JK, ?', '["LM","MN","NO","KL"]'::jsonb, 1, 'Cada bloco de 2 letras pula 1 letra em relação ao bloco anterior. Depois de JK (pulando L), vem MN.');
insert into questions (question, options, correct_index, explanation) values ('Qual letra mais se repete na palavra ''BANANA''?', '["B","A","N","Nenhuma se repete"]'::jsonb, 1, 'A letra ''A'' aparece 3 vezes em BANANA, mais que qualquer outra letra da palavra.');
insert into questions (question, options, correct_index, explanation) values ('Quantas vogais tem a palavra ''ABACAXI''?', '["3","4","5","2"]'::jsonb, 1, 'As vogais em ABACAXI são A, A, A, I — totalizando 4 vogais.');
insert into questions (question, options, correct_index, explanation) values ('Complete a sequência de letras: C, F, I, L, ?', '["M","N","O","P"]'::jsonb, 2, 'Cada letra avança 3 posições no alfabeto (C=3, F=6, I=9, L=12, O=15).');
insert into questions (question, options, correct_index, explanation) values ('Qual é a 5ª letra do alfabeto contando de trás para frente (Z sendo a 1ª)?', '["W","V","U","T"]'::jsonb, 1, 'Contando do final: Z(1), Y(2), X(3), W(4), V(5).');
insert into questions (question, options, correct_index, explanation) values ('Se 40% de um número é igual a 20, qual é esse número?', '["40","50","60","80"]'::jsonb, 1, 'Se 40% = 20, então o número total é 20 ÷ 0,4 = 50.');
insert into questions (question, options, correct_index, explanation) values ('Quanto mede cada ângulo interno de um triângulo equilátero?', '["45°","60°","90°","120°"]'::jsonb, 1, 'Em um triângulo equilátero, os 3 ângulos internos são iguais e somam 180°, logo cada um mede 60°.');
insert into questions (question, options, correct_index, explanation) values ('Se 1kg de maçãs custa R$6, quanto você paga por 2,5kg?', '["R$12","R$13,50","R$15","R$18"]'::jsonb, 2, '2,5 × R$6 = R$15.');
insert into questions (question, options, correct_index, explanation) values ('Quantos graus somam os ângulos internos de qualquer triângulo?', '["90°","180°","270°","360°"]'::jsonb, 1, 'A soma dos ângulos internos de qualquer triângulo é sempre 180°.');
insert into questions (question, options, correct_index, explanation) values ('Se a probabilidade de chover amanhã é 30%, qual é a probabilidade de NÃO chover?', '["30%","50%","70%","100%"]'::jsonb, 2, 'A soma das probabilidades de ocorrer e não ocorrer um evento é sempre 100%. 100% - 30% = 70%.');
