insert into questions (question, options, correct_index, explanation) values ('Qual é o animal terrestre mais rápido do mundo?', '["O leão","O cavalo","A chita (guepardo)","O avestruz"]'::jsonb, 2, 'A chita pode atingir mais de 100 km/h em curtas distâncias, sendo o animal terrestre mais rápido.');
insert into questions (question, options, correct_index, explanation) values ('Quantas cores tem o arco-íris tradicionalmente?', '["5","6","7","8"]'::jsonb, 2, 'O arco-íris tradicional é composto por 7 cores: vermelho, laranja, amarelo, verde, azul, anil e violeta.');
