insert into questions (question, options, correct_index, explanation) values ('Quem foi o primeiro presidente do Brasil?', '["Getúlio Vargas","Deodoro da Fonseca","Dom Pedro II","Prudente de Morais"]'::jsonb, 1, 'Marechal Deodoro da Fonseca foi o primeiro presidente do Brasil, após a Proclamação da República em 1889.');
insert into questions (question, options, correct_index, explanation) values ('Qual é a montanha mais alta do mundo?', '["K2","Monte Everest","Kilimanjaro","Aconcágua"]'::jsonb, 1, 'O Monte Everest, no Himalaia, é o ponto mais alto da Terra, com cerca de 8.849 metros.');
insert into questions (question, options, correct_index, explanation) values ('Quantos jogadores de cada time ficam em campo em uma partida oficial de futebol?', '["9","10","11","12"]'::jsonb, 2, 'Cada time de futebol tem 11 jogadores em campo, incluindo o goleiro.');
insert into questions (question, options, correct_index, explanation) values ('Qual é o menor osso do corpo humano?', '["A falange","O estribo (no ouvido)","A clavícula","A rótula"]'::jsonb, 1, 'O estribo, localizado no ouvido médio, é o menor osso do corpo humano.');
insert into questions (question, options, correct_index, explanation) values ('Em que ano começou a Segunda Guerra Mundial?', '["1935","1939","1941","1945"]'::jsonb, 1, 'A Segunda Guerra Mundial começou em 1939, com a invasão da Polônia pela Alemanha.');
insert into questions (question, options, correct_index, explanation) values ('Qual é a língua mais falada no mundo como idioma nativo?', '["Inglês","Espanhol","Mandarim","Hindi"]'::jsonb, 2, 'O mandarim é a língua com mais falantes nativos no mundo.');
insert into questions (question, options, correct_index, explanation) values ('Qual gás é mais abundante na atmosfera terrestre?', '["Oxigênio","Gás carbônico","Nitrogênio","Hidrogênio"]'::jsonb, 2, 'O nitrogênio compõe cerca de 78% da atmosfera terrestre.');
insert into questions (question, options, correct_index, explanation) values ('Quantos minutos tem uma partida oficial de futebol, sem prorrogação?', '["60","80","90","120"]'::jsonb, 2, 'Uma partida de futebol tem 90 minutos, divididos em dois tempos de 45.');
insert into questions (question, options, correct_index, explanation) values ('Qual é a capital do Canadá?', '["Toronto","Vancouver","Ottawa","Montreal"]'::jsonb, 2, 'Ottawa é a capital do Canadá, embora Toronto seja a cidade mais populosa.');
insert into questions (question, options, correct_index, explanation) values ('Quem escreveu a peça ''Romeu e Julieta''?', '["Charles Dickens","William Shakespeare","Oscar Wilde","Jane Austen"]'::jsonb, 1, '''Romeu e Julieta'' é uma das tragédias mais famosas de William Shakespeare.');
insert into questions (question, options, correct_index, explanation) values ('Qual é o maior país do mundo em área territorial?', '["China","Estados Unidos","Canadá","Rússia"]'::jsonb, 3, 'A Rússia é o maior país do mundo em área, ocupando partes da Europa e da Ásia.');
insert into questions (question, options, correct_index, explanation) values ('Quantos dentes tem, em média, um adulto humano, incluindo os sisos?', '["28","30","32","34"]'::jsonb, 2, 'Um adulto humano tem, em média, 32 dentes contando com os 4 sisos.');
insert into questions (question, options, correct_index, explanation) values ('Qual instrumento musical tem teclas pretas e brancas?', '["O violino","O piano","A flauta","O saxofone"]'::jsonb, 1, 'O piano é o instrumento clássico com teclas pretas e brancas.');
insert into questions (question, options, correct_index, explanation) values ('Em que continente fica o deserto do Saara?', '["Ásia","América do Sul","África","Oceania"]'::jsonb, 2, 'O Saara está localizado no norte do continente africano.');
insert into questions (question, options, correct_index, explanation) values ('Qual é a velocidade aproximada do som no ar?', '["34 m/s","340 m/s","3.400 m/s","34.000 m/s"]'::jsonb, 1, 'O som viaja a aproximadamente 340 metros por segundo no ar, ao nível do mar.');
insert into questions (question, options, correct_index, explanation) values ('Quantos planetas existem no sistema solar, sem contar Plutão (reclassificado como planeta anão)?', '["7","8","9","10"]'::jsonb, 1, 'Desde 2006, o sistema solar é oficialmente composto por 8 planetas.');
insert into questions (question, options, correct_index, explanation) values ('Qual é a capital da Argentina?', '["Córdoba","Rosário","Buenos Aires","Mendoza"]'::jsonb, 2, 'Buenos Aires é a capital e maior cidade da Argentina.');
insert into questions (question, options, correct_index, explanation) values ('Quem pintou a obra ''A Noite Estrelada''?', '["Pablo Picasso","Claude Monet","Vincent van Gogh","Salvador Dalí"]'::jsonb, 2, '''A Noite Estrelada'' é uma das obras mais famosas de Vincent van Gogh, pintada em 1889.');
insert into questions (question, options, correct_index, explanation) values ('Charada: quanto mais eu apago, mais eu ajudo. O que sou?', '["Uma borracha","Um apagador","Uma lousa","Um marca-texto"]'::jsonb, 0, 'A borracha só é útil quando apaga o que está escrito, corrigindo erros.');
insert into questions (question, options, correct_index, explanation) values ('Charada: tenho uma agulha que aponta sempre para o mesmo lado, mas não costuro nada. O que sou?', '["Um relógio","Uma bússola","Uma balança","Um velocímetro"]'::jsonb, 1, 'A agulha da bússola sempre aponta para o norte magnético.');
insert into questions (question, options, correct_index, explanation) values ('Charada: fecho tudo que você quer guardar, mas não tenho mãos. O que sou?', '["Uma gaveta","Um cadeado","Uma mala","Um cofre"]'::jsonb, 1, 'O cadeado é usado para trancar e proteger o que está guardado.');
insert into questions (question, options, correct_index, explanation) values ('Charada: caio do céu, mas não me machuco; sem mim, as plantas não crescem. O que sou?', '["O sol","A chuva","O vento","O orvalho"]'::jsonb, 1, 'A chuva cai do céu e é essencial para o crescimento das plantas.');
insert into questions (question, options, correct_index, explanation) values ('Charada: tenho luz própria à noite, mas de dia ninguém me nota. O que sou?', '["Uma estrela","A lua","Uma lanterna","Um vaga-lume"]'::jsonb, 1, 'A lua é visível à noite, mas passa despercebida durante o dia claro.');
insert into questions (question, options, correct_index, explanation) values ('Charada: nasço líquido, mas fico duro dentro do congelador. O que sou?', '["O gelo","A manteiga","O chocolate","A cera"]'::jsonb, 0, 'A água (líquida) se transforma em gelo (sólido) ao ser congelada.');
insert into questions (question, options, correct_index, explanation) values ('Charada: abro caminho no escuro, mas não tenho pernas. O que sou?', '["Uma porta","Uma lanterna","Uma chave","Uma janela"]'::jsonb, 1, 'A lanterna ilumina o caminho em lugares escuros.');
insert into questions (question, options, correct_index, explanation) values ('Charada: bato bem forte quando você se assusta, mas não tenho mãos. O que sou?', '["Um tambor","O coração","Um sino","Um despertador"]'::jsonb, 1, 'O coração bate mais forte e rápido em momentos de emoção ou susto.');
insert into questions (question, options, correct_index, explanation) values ('Charada: só apareço quando o sol se põe e desapareço quando ele nasce. O que sou?', '["A lua cheia","A noite","O crepúsculo","A madrugada"]'::jsonb, 1, 'A noite começa ao pôr do sol e termina com o nascer do sol.');
insert into questions (question, options, correct_index, explanation) values ('Charada: tenho várias teclas, mas não abro nenhuma porta; faço música quando você me toca. O que sou?', '["Um piano","Um teclado de computador","Uma sanfona","Um violão"]'::jsonb, 0, 'O piano tem teclas usadas para produzir música, não para abrir portas.');
insert into questions (question, options, correct_index, explanation) values ('Charada: escorro pela sua bochecha quando você fica muito triste ou muito feliz. O que sou?', '["Uma gota de suor","Uma lágrima","Uma gota de chuva","Uma bolha"]'::jsonb, 1, 'As lágrimas podem surgir tanto em momentos de tristeza quanto de emoção intensa e alegria.');
insert into questions (question, options, correct_index, explanation) values ('Charada: tenho penas, mas não voo; ajudo a escrever à moda antiga. O que sou?', '["Uma pena de escrever","Um travesseiro","Um leque","Uma flecha"]'::jsonb, 0, 'Antigamente, penas de aves eram usadas como caneta para escrever.');
insert into questions (question, options, correct_index, explanation) values ('Charada: sou uma casa sem portas nem janelas, e quem está lá dentro quer sair. O que sou?', '["Um ovo","Uma caverna","Um cofre","Uma caixa"]'::jsonb, 0, 'O filhote dentro do ovo precisa quebrar a casca para poder sair.');
insert into questions (question, options, correct_index, explanation) values ('Charada: quanto mais eu ando, menos caminho me resta, mas nunca chego a lugar nenhum de verdade. O que sou?', '["Uma esteira","Uma bicicleta","Um carrossel","Uma escada rolante"]'::jsonb, 0, 'Na esteira de academia, você caminha ou corre, mas permanece sempre no mesmo lugar.');
insert into questions (question, options, correct_index, explanation) values ('Charada: tenho corpo, mas não tenho alma; ganho forma quando você me veste. O que sou?', '["Um espantalho","Um manequim","Uma boneca","Um travesseiro"]'::jsonb, 1, 'O manequim ganha a aparência de uma pessoa vestida, mas não tem vida.');
insert into questions (question, options, correct_index, explanation) values ('Charada: sou feito de água congelada, mas posso machucar quem estiver lá fora quando eu caio do céu. O que sou?', '["A neve","O granizo","O orvalho","A geada"]'::jsonb, 1, 'O granizo é formado por pedras de gelo que caem durante tempestades, podendo causar estragos.');
insert into questions (question, options, correct_index, explanation) values ('Charada: nasço nas nuvens e brilho no céu logo depois da chuva parar. O que sou?', '["Um raio","Um arco-íris","Uma estrela cadente","Um relâmpago"]'::jsonb, 1, 'O arco-íris aparece quando a luz do sol atravessa gotas de chuva no ar.');
insert into questions (question, options, correct_index, explanation) values ('Charada: sirvo para prender folhas de papel, mas não tenho mãos nem cola. O que sou?', '["Um clipe","Uma fita adesiva","Um grampeador","Uma pasta"]'::jsonb, 0, 'O clipe prende papéis apenas pela pressão do seu formato dobrado, sem cola.');
insert into questions (question, options, correct_index, explanation) values ('Charada: sou pequena, mas sem mim, o cadeado não abre. O que sou?', '["Uma senha","Uma chave","Uma fechadura","Um alarme"]'::jsonb, 1, 'A chave é o objeto pequeno necessário para destrancar um cadeado.');
insert into questions (question, options, correct_index, explanation) values ('Charada: encho de ar, mas não respiro; estouro com a picada de um alfinete. O que sou?', '["Um pneu","Um balão","Uma bola","Um colchão inflável"]'::jsonb, 1, 'O balão é enchido com ar (ou gás) e estoura facilmente ao ser furado.');
insert into questions (question, options, correct_index, explanation) values ('Se hoje é quinta-feira, que dia da semana será daqui a 200 dias?', '["Domingo","Segunda-feira","Terça-feira","Sábado"]'::jsonb, 1, '200 dividido por 7 deixa resto 4. Avançando 4 dias a partir de quinta: sexta, sábado, domingo, segunda-feira.');
insert into questions (question, options, correct_index, explanation) values ('Uma caixa contém 8 bolas vermelhas e 8 bolas azuis, todas soltas. Quantas bolas você precisa tirar, no mínimo, para garantir 3 da mesma cor?', '["3","4","5","6"]'::jsonb, 2, 'No pior caso, você tira 2 de cada cor (4 no total) sem formar trio. A 5ª bola garante 3 da mesma cor.');
insert into questions (question, options, correct_index, explanation) values ('Se o dobro de um número mais 5 é igual a 21, qual é esse número?', '["6","7","8","9"]'::jsonb, 2, '2x + 5 = 21 → 2x = 16 → x = 8.');
insert into questions (question, options, correct_index, explanation) values ('Numa fila, Marcos está na 5ª posição contando da frente e na 8ª posição contando de trás. Quantas pessoas há na fila?', '["11","12","13","14"]'::jsonb, 1, 'Total = 5 + 8 - 1 (Marcos contado duas vezes) = 12 pessoas.');
insert into questions (question, options, correct_index, explanation) values ('Se 3 canetas custam R$9, quanto custam 7 canetas do mesmo tipo?', '["R$18","R$21","R$24","R$15"]'::jsonb, 1, 'Cada caneta custa R$3 (9÷3). 7 canetas custam 7 × R$3 = R$21.');
insert into questions (question, options, correct_index, explanation) values ('Um código transforma cada letra na letra seguinte do alfabeto (A→B, B→C...). Qual é o código da palavra ''CASA''?', '["DBTB","DBTA","DATB","DBUB"]'::jsonb, 0, 'C→D, A→B, S→T, A→B, formando ''DBTB''.');
insert into questions (question, options, correct_index, explanation) values ('Se depois de amanhã é sexta-feira, que dia da semana é hoje?', '["Terça-feira","Quarta-feira","Quinta-feira","Sexta-feira"]'::jsonb, 1, 'Depois de amanhã é hoje + 2 dias. Se hoje + 2 = sexta, hoje é quarta-feira.');
insert into questions (question, options, correct_index, explanation) values ('Numa prateleira há livros numerados de 1 a 50. Quantos desses números contêm o algarismo 5?', '["5","6","7","8"]'::jsonb, 1, 'Os números são: 5, 15, 25, 35, 45 e 50 — total de 6 números com o algarismo 5.');
insert into questions (question, options, correct_index, explanation) values ('Se A é irmão de B, e B é irmão de C, o que podemos afirmar sobre A e C?', '["A e C também são irmãos","A e C não têm relação necessária","C é pai de A","Não é possível determinar nada"]'::jsonb, 0, 'Sendo o parentesco de irmãos definido por compartilhar os mesmos pais, essa relação é transitiva: A e C também são irmãos.');
insert into questions (question, options, correct_index, explanation) values ('Se X + Y = 10 e X - Y = 4, qual é o valor de X?', '["6","7","8","5"]'::jsonb, 1, 'Somando as duas equações: 2X = 14 → X = 7.');
insert into questions (question, options, correct_index, explanation) values ('Numa sala com 5 pessoas, cada uma aperta a mão de todas as outras exatamente uma vez. Quantos apertos de mão acontecem ao todo?', '["8","9","10","12"]'::jsonb, 2, 'O total de combinações de 2 pessoas entre 5 é 10 (fórmula de combinação C(5,2) = 10).');
insert into questions (question, options, correct_index, explanation) values ('Quantos graus o ponteiro das horas de um relógio percorre em 4 horas?', '["90°","100°","120°","150°"]'::jsonb, 2, 'O ponteiro das horas percorre 30° a cada hora. Em 4 horas: 4 × 30° = 120°.');
insert into questions (question, options, correct_index, explanation) values ('Se todos os Xandu são Ypsilon, e nenhum Ypsilon é Zeta, o que podemos concluir?', '["Todo Zeta é Xandu","Nenhum Xandu é Zeta","Algum Xandu é Zeta","Todo Ypsilon é Xandu"]'::jsonb, 1, 'Se Xandu está contido em Ypsilon, e Ypsilon não tem interseção com Zeta, então Xandu também não tem interseção com Zeta.');
insert into questions (question, options, correct_index, explanation) values ('Numa corrida, Ana termina antes de Bruno, mas depois de Carla. Diego termina antes de Carla. Quem venceu a corrida?', '["Ana","Bruno","Carla","Diego"]'::jsonb, 3, 'A ordem de chegada é: Diego, Carla, Ana, Bruno — portanto Diego venceu.');
insert into questions (question, options, correct_index, explanation) values ('Um código transforma cada número em seu dobro menos 1 (regra: n → 2n-1). Qual número originou o resultado 15?', '["6","7","8","9"]'::jsonb, 2, '2n - 1 = 15 → 2n = 16 → n = 8.');
